        return 'Choice(%r)' % list(self.choices)

","new":"class Choice(ParamType):
    """The choice type allows a value to be checked against a fixed set of
    supported values.  All of these values have to be strings.

    You should only pass *choices* as list or tuple.  Other iterables (like
    generators) may lead to surprising results.

    See :ref:`choice-opts` for an example.
    """
    name = 'choice'

    def __init__(self, choices, case_sensitive=True):
        self.choices = choices
        self.case_sensitive = case_sensitive

    def get_metavar(self, param):
        return '[%s]' % '|'.join(self.choices)

    def get_missing_message(self, param):
        return 'Choose from %s.' % ', '.join(self.choices)

    def normalize_choice(self, choice, ctx):
        if not self.case_sensitive:
            choice = choice.lower()

        if ctx is not None and \
           ctx.token_normalize_func is not None:
            choice = ctx.token_normalize_func(choice)

        return choice

    def convert(self, value, param, ctx):
        # Exact match
        if value in self.choices:
            return value

        normalized_value = value
        if not self.case_sensitive:
            normalized_value = normalized_value.lower()

        # Match through normalization
        if ctx is not None and \
           ctx.token_normalize_func is not None:
            normalized_value = ctx.token_normalize_func(normalized_value)

        for choice in self.choices:
            if self.normalize_choice(choice, ctx) == normalized_value:
                return choice

        self.fail('invalid choice: %s. (choose from %s)' %
                  (value, ', '.join(self.choices)), param, ctx)

    def __repr__(self):
        if self.case_sensitive:
            return 'Choice(%r)' % list(self.choices)
        return 'Choice(%r, case_sensitive=False)' % list(self.choices)

